          <strong>How it works:</strong> Every day, the system compares each train's <strong>actual mileage</strong> to 
          its <strong>planned mileage</strong> (from the <Term term="Master Plan">Master Plan</Term>) and calculates 
          the <Term term="Drift">drift</Term>. Based on drift, it assigns a <Term term="RUC">RUC</Term> category.
        </p>
      </div>

      {/* RUC Categories */}
      <div className="grid grid-cols-3 gap-6 mb-6">
        {/* ACCELERATE */}
        <div className="bg-gradient-to-br from-red-50 to-red-100 rounded-2xl p-5 border-2 border-red-200">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-12 h-12 bg-red-500 rounded-xl flex items-center justify-center">
              <TrendingUp className="w-7 h-7 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold text-red-700">ACCELERATE</h3>
              <p className="text-sm text-red-500">Negative <Term term="Drift">drift</Term> (behind)</p>
            </div>
          </div>

          <div className="bg-white rounded-xl p-4 mb-3">
            <p className="text-sm font-semibold text-gray-700 mb-2">What it means:</p>
            <p className="text-sm text-gray-600">
              Train has accumulated <strong>less km</strong> than planned. Needs to "catch up" to reach 
              <Term term="PM50k"> PM threshold</Term> on schedule.
            </p>
          </div>

          <div className="bg-red-200/50 rounded-xl p-4">
            <p className="text-sm font-semibold text-red-700 mb-2">Actions:</p>
            <ul className="text-sm text-red-600 space-y-1">
              <li>→ Assign to longer routes (Red Line)</li>
              <li>→ Prioritize for peak hours</li>
              <li>→ Avoid keeping as spare</li>
            </ul>
          </div>
        </div>

        {/* NOMINAL */}
        <div className="bg-gradient-to-br from-green-50 to-green-100 rounded-2xl p-5 border-2 border-green-200">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-12 h-12 bg-green-500 rounded-xl flex items-center justify-center">
              <Minus className="w-7 h-7 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold text-green-700">NOMINAL</h3>
              <p className="text-sm text-green-500"><Term term="Drift">Drift</Term> ≈ 0 (on track)</p>
            </div>
          </div>

          <div className="bg-white rounded-xl p-4 mb-3">
            <p className="text-sm font-semibold text-gray-700 mb-2">What it means:</p>
            <p className="text-sm text-gray-600">
              Train is <strong>aligned</strong> with the <Term term="Master Plan">Master Plan</Term>. 
              Current trajectory will hit maintenance on schedule.
            </p>
          </div>

          <div className="bg-green-200/50 rounded-xl p-4">
            <p className="text-sm font-semibold text-green-700 mb-2">Actions:</p>
            <ul className="text-sm text-green-600 space-y-1">
              <li>→ Normal assignment</li>
              <li>→ Standard rotation</li>
              <li>→ No special treatment needed</li>
            </ul>
          </div>
        </div>

        {/* DECELERATE */}
        <div className="bg-gradient-to-br from-amber-50 to-amber-100 rounded-2xl p-5 border-2 border-amber-200">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-12 h-12 bg-amber-500 rounded-xl flex items-center justify-center">
              <TrendingDown className="w-7 h-7 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold text-amber-700">DECELERATE</h3>
              <p className="text-sm text-amber-500">Positive <Term term="Drift">drift</Term> (ahead)</p>
            </div>
          </div>

          <div className="bg-white rounded-xl p-4 mb-3">
            <p className="text-sm font-semibold text-gray-700 mb-2">What it means:</p>
            <p className="text-sm text-gray-600">
              Train has accumulated <strong>more km</strong> than planned. Needs to "slow down" to avoid 
              early <Term term="PM">maintenance</Term>.
            </p>
          </div>

          <div className="bg-amber-200/50 rounded-xl p-4">
            <p className="text-sm font-semibold text-amber-700 mb-2">Actions:</p>
            <ul className="text-sm text-amber-600 space-y-1">
              <li>→ Assign to shorter routes (Green Line)</li>
              <li>→ Use as spare when possible</li>
              <li>→ Reduce usage frequency</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Live Demo Table */}
      <div className="bg-white rounded-xl shadow-lg p-5">
        <h3 className="font-bold text-gray-700 mb-4 flex items-center gap-2">
          <RefreshCw className="w-5 h-5 text-blue-500" />
          Live Fleet Status (Example Dashboard)
        </h3>

        <div className="overflow-hidden rounded-lg border border-gray-200">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-semibold text-gray-600">Train ID</th>
                <th className="px-4 py-3 text-left text-sm font-semibold text-gray-600">Fleet</th>
                <th className="px-4 py-3 text-right text-sm font-semibold text-gray-600">Planned km</th>
                <th className="px-4 py-3 text-right text-sm font-semibold text-gray-600">Actual km</th>
                <th className="px-4 py-3 text-right text-sm font-semibold text-gray-600"><Term term="Drift">Drift</Term></th>
                <th className="px-4 py-3 text-center text-sm font-semibold text-gray-600"><Term term="RUC">RUC</Term></th>
                <th className="px-4 py-3 text-left text-sm font-semibold text-gray-600">Recommendation</th>
              </tr>
            </thead>
            <tbody>
              {trainData.map((train, idx) => {
                const drift = train.actual - train.planned;
                const driftPct = ((drift / train.planned) * 100).toFixed(1);
                const ruc = getRUC(train.status);
                return (
                  <tr key={train.id} className={`border-t ${idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}`}>
                    <td className="px-4 py-3 font-mono text-sm">{train.id}</td>
                    <td className="px-4 py-3 text-sm">{train.fleet}</td>
                    <td className="px-4 py-3 text-right text-sm">{train.planned.toLocaleString()}</td>
                    <td className="px-4 py-3 text-right text-sm">{train.actual.toLocaleString()}</td>
                    <td className={`px-4 py-3 text-right text-sm font-semibold ${
                      drift > 0 ? 'text-amber-600' : drift < 0 ? 'text-red-600' : 'text-green-600'
                    }`}>
                      {drift > 0 ? '+' : ''}{drift.toLocaleString()} ({driftPct}%)
                    </td>
                    <td className="px-4 py-3 text-center">
                      <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold text-white ${ruc.color}`}>
                        <ruc.icon className="w-3 h-3" />
                        {ruc.label}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-sm text-gray-600">{ruc.action}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  // ============================================
  // SLIDE: COMPLETE INTEGRATION
  // ============================================
  const IntegrationSlide = () => (
    <div className="space-y-6">
      <div className="text-center mb-6">
        <h2 className="text-3xl font-bold text-gray-800">Complete System Flow</h2>
        <p className="text-gray-500 mt-2">From data input to actionable recommendations</p>
      </div>

      {/* Full flow diagram */}
      <div className="bg-gradient-to-br from-gray-50 to-gray-100 rounded-2xl p-8">
        <div className="flex flex-col items-center gap-4">
          {/* Row 1: Inputs */}
          <div className="flex gap-4">
            <div className="bg-blue-100 rounded-xl p-4 text-center w-36 border-2 border-blue-200">
              <Database className="w-8 h-8 mx-auto text-blue-600 mb-2" />
              <p className="text-sm font-semibold"><Term term="Maximo">IBM Maximo</Term></p>
              <p className="text-xs text-gray-500">Asset data</p>
            </div>
            <div className="bg-blue-100 rounded-xl p-4 text-center w-36 border-2 border-blue-200">
              <Train className="w-8 h-8 mx-auto text-blue-600 mb-2" />
              <p className="text-sm font-semibold">Daily Mileage</p>
              <p className="text-xs text-gray-500">Automatic import</p>
            </div>
            <div className="bg-blue-100 rounded-xl p-4 text-center w-36 border-2 border-blue-200">
              <Settings className="w-8 h-8 mx-auto text-blue-600 mb-2" />
              <p className="text-sm font-semibold"><Term term="PM">PM</Term> Rules</p>
              <p className="text-xs text-gray-500">Configurable intervals</p>
            </div>
            <div className="bg-blue-100 rounded-xl p-4 text-center w-36 border-2 border-blue-200">
              <Users className="w-8 h-8 mx-auto text-blue-600 mb-2" />
              <p className="text-sm font-semibold">Resources</p>
              <p className="text-xs text-gray-500">Tracks, <Term term="Man-hours">labor</Term></p>
            </div>
          </div>

          <ArrowDown className="w-8 h-8 text-gray-400" />

          {/* Row 2: Core Engine */}
          <div className="bg-gradient-to-r from-purple-500 to-indigo-600 rounded-2xl p-6 text-white w-full max-w-2xl shadow-xl">
            <div className="flex items-center justify-center gap-4 mb-4">
              <Cpu className="w-10 h-10" />
              <div>
                <h3 className="text-xl font-bold">MMS Core Engine</h3>
                <p className="text-purple-200 text-sm">Forecast → <Term term="MIP">Optimize</Term> → Recommend</p>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-3">
              <div className="bg-white/20 rounded-lg p-3 text-center">
                <p className="font-semibold text-sm">Strategic</p>
                <p className="text-xs text-purple-100">12-year <Term term="Master Plan">plan</Term></p>
              </div>
              <div className="bg-white/20 rounded-lg p-3 text-center">
                <p className="font-semibold text-sm">Tactical</p>
                <p className="text-xs text-purple-100">Daily <Term term="RUC">RUC</Term></p>
              </div>
              <div className="bg-white/20 rounded-lg p-3 text-center">
                <p className="font-semibold text-sm">Monitoring</p>
                <p className="text-xs text-purple-100"><Term term="Drift">Drift</Term> alerts</p>
              </div>
            </div>
          </div>

          <ArrowDown className="w-8 h-8 text-gray-400" />

          {/* Row 3: Outputs */}
          <div className="flex gap-4">
            <div className="bg-green-100 rounded-xl p-4 text-center w-36 border-2 border-green-200">
              <Calendar className="w-8 h-8 mx-auto text-green-600 mb-2" />
              <p className="text-sm font-semibold"><Term term="Master Plan">Master Plan</Term></p>
              <p className="text-xs text-gray-500">12-year schedule</p>
            </div>
            <div className="bg-green-100 rounded-xl p-4 text-center w-36 border-2 border-green-200">
              <Target className="w-8 h-8 mx-auto text-green-600 mb-2" />
              <p className="text-sm font-semibold">Daily <Term term="RUC">RUC</Term></p>
              <p className="text-xs text-gray-500">Per-train guidance</p>
            </div>
            <div className="bg-green-100 rounded-xl p-4 text-center w-36 border-2 border-green-200">
              <Bell className="w-8 h-8 mx-auto text-green-600 mb-2" />
              <p className="text-sm font-semibold">Alerts</p>
              <p className="text-xs text-gray-500">Email notifications</p>
            </div>
            <div className="bg-green-100 rounded-xl p-4 text-center w-36 border-2 border-green-200">
              <FileText className="w-8 h-8 mx-auto text-green-600 mb-2" />
              <p className="text-sm font-semibold">Reports</p>
              <p className="text-xs text-gray-500">PDF, Excel</p>
            </div>
          </div>

          <ArrowDown className="w-8 h-8 text-gray-400" />

          {/* Row 4: Users */}
          <div className="flex gap-8">
            <div className="bg-amber-100 rounded-xl p-4 text-center w-48 border-2 border-amber-200">
              <Wrench className="w-8 h-8 mx-auto text-amber-600 mb-2" />
              <p className="text-sm font-semibold">Maintenance Team</p>
              <p className="text-xs text-gray-500">Workshop scheduling</p>
            </div>
            <div className="bg-amber-100 rounded-xl p-4 text-center w-48 border-2 border-amber-200">
              <Train className="w-8 h-8 mx-auto text-amber-600 mb-2" />
              <p className="text-sm font-semibold">Operations Team</p>
              <p className="text-xs text-gray-500">Run assignments</p>
            </div>
            <div className="bg-amber-100 rounded-xl p-4 text-center w-48 border-2 border-amber-200">
              <BarChart3 className="w-8 h-8 mx-auto text-amber-600 mb-2" />
              <p className="text-sm font-semibold">Management</p>
              <p className="text-xs text-gray-500">Cost compliance</p>
            </div>
          </div>
        </div>
      </div>

      {/* Daily cycle timeline */}
      <div className="bg-white rounded-xl shadow-lg p-5">
        <h3 className="font-bold text-gray-700 mb-4">Daily Automatic Cycle</h3>
        <div className="flex items-center justify-between">
          {[
            { time: '06:00', label: 'Import mileage', icon: Database, bg: 'bg-blue-50', color: 'text-blue-500' },
            { time: '06:05', label: 'Calculate RUC', icon: Cpu, bg: 'bg-purple-50', color: 'text-purple-500' },
            { time: '06:10', label: 'Generate recommendations', icon: Target, bg: 'bg-green-50', color: 'text-green-500' },
            { time: '06:15', label: 'Update dashboard', icon: BarChart3, bg: 'bg-amber-50', color: 'text-amber-500' },
            { time: '06:20', label: 'Send alerts (if needed)', icon: Bell, bg: 'bg-red-50', color: 'text-red-500' },
          ].map((step, idx) => (
            <React.Fragment key={step.time}>
              <div className={`flex flex-col items-center p-3 rounded-xl ${step.bg}`}>
                <step.icon className={`w-6 h-6 ${step.color} mb-1`} />
                <p className="text-sm font-bold text-gray-700">{step.time}</p>
                <p className="text-xs text-gray-500 text-center">{step.label}</p>
              </div>
              {idx < 4 && <ChevronRight className="w-5 h-5 text-gray-300" />}
            </React.Fragment>
          ))}
        </div>
      </div>
    </div>
  );

  // ============================================
  // RENDER CURRENT SLIDE
  // ============================================
  const renderSlide = () => {
    switch (slides[currentSlide].id) {
      case 'intro': return <IntroSlide />;
      case 'problem': return <ProblemSlide />;
      case 'solution': return <SolutionSlide />;
      case 'strategic': return <StrategicSlide />;
      case 'tactical': return <TacticalSlide />;
      case 'integration': return <IntegrationSlide />;
      default: return <IntroSlide />;
    }
  };

  // ============================================
  // MAIN RENDER
  // ============================================
  return (
    <div className="min-h-screen bg-gray-100">
      {/* Glossary Panel */}
      <GlossaryPanel isOpen={showGlossary} onClose={() => setShowGlossary(false)} />

      {/* Header */}
      <div className="bg-gradient-to-r from-slate-800 to-slate-900 text-white px-6 py-4">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <Train className="w-8 h-8 text-blue-400" />
              <div>
                <h1 className="text-xl font-bold">Mileage Management System</h1>
                <p className="text-slate-400 text-sm">Technical Architecture Presentation</p>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button
              onClick={() => setShowGlossary(true)}
              className="flex items-center gap-2 bg-white/10 hover:bg-white/20 rounded-lg px-4 py-2 transition-colors"
            >
              <Book className="w-5 h-5" />
              <span className="text-sm font-medium">Glossary</span>
            </button>
            <div className="bg-white/10 rounded-lg px-4 py-2">
              <span className="text-sm font-semibold">Dubai Metro | Keolis MHI</span>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-6 py-3">
          <div className="flex items-center gap-2">
            {slides.map((slide, idx) => (
              <button
                key={slide.id}
                onClick={() => setCurrentSlide(idx)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
                  currentSlide === idx
                    ? 'bg-blue-500 text-white shadow-md'
                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${
                  currentSlide === idx ? 'bg-white/20' : 'bg-gray-300'
                }`}>
                  {idx + 1}
                </span>
                <span className="text-sm font-medium">{slide.title}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="max-w-7xl mx-auto px-6 py-8">
        <div className="bg-white rounded-2xl shadow-xl p-8 min-h-[600px]">
          {renderSlide()}
        </div>
      </div>

      {/* Footer navigation */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t shadow-lg">
        <div className="max-w-7xl mx-auto px-6 py-3 flex items-center justify-between">
          <button
            onClick={() => setCurrentSlide(prev => Math.max(0, prev - 1))}
            disabled={currentSlide === 0}
            className={`px-4 py-2 rounded-lg font-medium ${
              currentSlide === 0 
                ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
            }`}
          >
            ← Previous
          </button>

          <div className="flex items-center gap-2">
            {slides.map((_, idx) => (
              <div
                key={idx}
                className={`w-2 h-2 rounded-full transition-all ${
                  idx === currentSlide ? 'bg-blue-500 w-6' : 'bg-gray-300'
                }`}
              />
            ))}
          </div>

          <button
            onClick={() => setCurrentSlide(prev => Math.min(slides.length - 1, prev + 1))}
            disabled={currentSlide === slides.length - 1}
            className={`px-4 py-2 rounded-lg font-medium ${
              currentSlide === slides.length - 1
                ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                : 'bg-blue-500 text-white hover:bg-blue-600'
            }`}
          >
            Next →
          </button>
        </div>
      </div>

      {/* Spacer for fixed footer */}
      <div className="h-20" />
    </div>
  );
};

export default MMSPresentation;
